-- Sales Pipeline dashboard table (mirrors the LeadList Attended/Unattended sheet).
-- Run this once in the Supabase SQL editor.

CREATE TABLE IF NOT EXISTS public.pipeline_leads (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  tab TEXT NOT NULL DEFAULT 'attended',          -- 'attended' | 'unattended'
  sl_no INTEGER,
  client TEXT,
  industry TEXT,
  requirement TEXT,
  estimated_value TEXT,
  current_stage TEXT,
  next_step TEXT,
  expected_closure TEXT,
  technical_notes TEXT,
  business TEXT,
  status TEXT,
  email TEXT,
  phone TEXT,
  description TEXT
);

CREATE INDEX IF NOT EXISTS idx_pipeline_leads_tab ON public.pipeline_leads (tab);
CREATE INDEX IF NOT EXISTS idx_pipeline_leads_created_at ON public.pipeline_leads (created_at DESC);

ALTER TABLE public.pipeline_leads ENABLE ROW LEVEL SECURITY;

-- The dashboard is behind an app-level login. These policies let the app read
-- and manage rows with the anon key (same posture as the existing lead tables).
CREATE POLICY "pipeline read"   ON public.pipeline_leads FOR SELECT TO anon, authenticated USING (true);
CREATE POLICY "pipeline insert" ON public.pipeline_leads FOR INSERT TO anon, authenticated WITH CHECK (true);
CREATE POLICY "pipeline update" ON public.pipeline_leads FOR UPDATE TO anon, authenticated USING (true) WITH CHECK (true);
CREATE POLICY "pipeline delete" ON public.pipeline_leads FOR DELETE TO anon, authenticated USING (true);

